import React from 'react';
import { AlertCircle, Loader2 } from 'lucide-react';

import NodeSelectionPanel from '../../../components/NodeSelectionPanel';
import { Button } from '../../../components/ui/button';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '../../../components/ui/card';
import { Input } from '../../../components/ui/input';
import { Label } from '../../../components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../../components/ui/select';
import { Tag } from '../../../components/ui/tag';
import { PreviewTable } from '../components/PreviewTable';
import { useReplaceSubTab, type ReplaceSubTabProps } from './hooks/useReplaceSubTab';

export type { ReplaceSubTabProps } from './hooks/useReplaceSubTab';

export const ReplaceSubTab: React.FC<ReplaceSubTabProps> = (props) => {
  const {
    activeNodeId,
    hasSelection,
    effectiveNodes,
    stringColumns,
    selectedColumn,
    setSelectedColumn,
    mode,
    setMode,
    count,
    n,
    setN,
    pattern,
    setPattern,
    replacement,
    setReplacement,
    connector,
    setConnector,
    outputColumnName,
    setOutputColumnName,
    resolvedOutputColumnName,
    controlsDisabled,
    canApply,
    applyLoading,
    handleApply,
    nodeColors,
    defaultPalette,
    selectedNodes,
    preview,
  } = useReplaceSubTab(props);

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader className="space-y-0 pb-4">
          <div className="flex flex-col gap-2 md:flex-row md:items-start md:justify-between">
            <div>
              <CardTitle>Find &amp; transform with regex</CardTitle>
              <CardDescription>
                Find regex matches in a text column and replace or extract them. Leave the output column blank to overwrite the source column.
              </CardDescription>
            </div>
            {preview.loading && (
              <Tag tone="muted">
                <Loader2 className="h-3.5 w-3.5 animate-spin" />
                Refreshing preview…
              </Tag>
            )}
          </div>
        </CardHeader>
        <CardContent className="space-y-6 pt-0">
          <NodeSelectionPanel
            selectedNodes={effectiveNodes}
            nodeColumnSelections={activeNodeId ? [{ nodeId: activeNodeId, column: selectedColumn }] : []}
            onColumnChange={(nodeId, column) => {
              if (nodeId === activeNodeId) {
                setSelectedColumn(column);
              }
            }}
            nodeColors={nodeColors}
            onColorChange={() => {}}
            defaultPalette={defaultPalette}
            maxCompare={1}
            className="rounded-lg border border-border/60 bg-muted/40"
            showColorPicker={false}
            showColumnPicker
            showHeaderLabel
            showShape
            disabled={controlsDisabled}
            originalCount={selectedNodes.length}
            allowedDataTypes={['string']}
            fallbackToAllColumns={false}
            statusMessage={
              hasSelection && stringColumns.length === 0
                ? 'The selected data block has no string columns available for regex operations.'
                : undefined
            }
          />

          <div className="flex flex-wrap items-end gap-3">
            <div className="w-32 space-y-2">
              <Label htmlFor="find-mode">Mode</Label>
              <Select value={mode} onValueChange={(value: 'replace' | 'extract') => setMode(value)} disabled={controlsDisabled || !selectedColumn}>
                <SelectTrigger id="find-mode">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="replace">Replace</SelectItem>
                  <SelectItem value="extract">Extract</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="w-44 space-y-2">
              <Label htmlFor="find-n">Match count</Label>
              <Input
                id="find-n"
                type="number"
                min={1}
                value={n ?? ''}
                onChange={(event) => setN(event.target.value ? Number(event.target.value) : null)}
                placeholder="All if left blank"
                disabled={controlsDisabled || !selectedColumn}
              />
            </div>

            <div className="min-w-0 flex-1 space-y-2">
              <Label htmlFor="find-pattern">Regex pattern</Label>
              <Input
                id="find-pattern"
                value={pattern}
                onChange={(event) => setPattern(event.target.value)}
                placeholder="\\d+"
                disabled={controlsDisabled || !selectedColumn}
              />
            </div>

            {mode === 'replace' ? (
              <>
                <span className="mb-2 text-sm text-muted-foreground">with</span>
                <div className="min-w-0 flex-1 space-y-2">
                  <Label htmlFor="find-replacement">Replacement</Label>
                  <Input
                    id="find-replacement"
                    value={replacement}
                    onChange={(event) => setReplacement(event.target.value)}
                    placeholder="#"
                    disabled={controlsDisabled || !selectedColumn}
                  />
                </div>
              </>
            ) : (
              <>
                <span className="mb-2 text-sm text-muted-foreground">join with</span>
                <div className="w-56 max-w-full space-y-2">
                  <Label htmlFor="find-connector">Connector</Label>
                  <Input
                    id="find-connector"
                    value={connector}
                    onChange={(event) => setConnector(event.target.value)}
                    placeholder={'" " will be used by default'}
                    disabled={controlsDisabled || !selectedColumn}
                  />
                </div>
              </>
            )}
          </div>

          <p className="text-xs text-muted-foreground">
            {mode === 'replace'
              ? count === 'all'
                ? 'Uses Polars Expr.str.replace_all — replaces every regex match in each value.'
                : `Uses Polars Expr.str.replace(n=${n ?? 1}) — replaces the first ${n ?? 1} regex match(es) in each value.`
              : count === 'all'
                ? `Extracts all regex matches and joins them with the connector.`
                : `Extracts the first ${n ?? 1} regex match(es) and joins them with the connector.`}
          </p>

          <div className="space-y-2">
            <Label htmlFor="replace-output-column">Output column name</Label>
            <Input
              id="replace-output-column"
              value={outputColumnName}
              onChange={(event) => setOutputColumnName(event.target.value)}
              placeholder={selectedColumn || 'Leave blank to overwrite the selected column'}
              disabled={controlsDisabled || !selectedColumn}
            />
            <p className="text-xs text-muted-foreground">When blank, the result is written back to <span className="font-medium text-foreground">{selectedColumn || 'the selected column'}</span>.</p>
          </div>
        </CardContent>
        <CardFooter className="flex flex-col gap-3 border-t border-border bg-muted/20 py-4 sm:flex-row sm:items-center sm:justify-between">
          <div className="text-sm text-muted-foreground">
            <p>Source column: {selectedColumn || 'Select a string column'}</p>
            <p>Output column: {resolvedOutputColumnName || 'Select a string column'}</p>
          </div>
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center">
            {preview.error && (
              <div className="flex items-center gap-2 text-sm text-destructive">
                <AlertCircle className="h-4 w-4" />
                <span>{preview.error}</span>
              </div>
            )}
            <Button type="button" onClick={() => void handleApply()} disabled={!canApply}>
              {applyLoading ? 'Applying…' : 'Add to Data Block'}
            </Button>
          </div>
        </CardFooter>
      </Card>

      <PreviewTable
        title="Preview results"
        description="Review the updated rows before applying to the selected data block."
        columns={preview.columns}
        data={preview.data}
        pagination={preview.pagination}
        loading={preview.loading}
        error={preview.error}
        ready={preview.ready}
        readyMessage={preview.readyMessage}
        page={preview.page}
        pageSize={preview.pageSize}
        onPageSizeChange={preview.setPageSize}
        onPreviousPage={preview.onPreviousPage}
        onNextPage={preview.onNextPage}
      />
    </div>
  );
};

export default ReplaceSubTab;